function mergeTwoLists(l1, l2) {
    let mergedList = [];
    while (l1.length > 0) {
        mergedList.push(l1.shift());
    }
    while (l2.length > 0) {
        mergedList.push(l2.shift());
    }
    mergedList.sort((a, b) => a - b);
    return mergedList;
}

