class Solution {
    public int[] mergeTwoLists(int[] l1, int[] l2) {
        int[] merged = new int[l1.length + l2.length];
        System.arraycopy(l1, 0, merged, 0, l1.length);
        System.arraycopy(l2, 0, merged, l1.length, l2.length);
        java.util.Arrays.sort(merged);
        return merged;
    }
}

