class Solution {
    public:
    vector<int> mergeTwoLists(const vector<int>& l1, const vector<int>& l2) {
        vector<int> mergedList;
        mergedList.reserve(l1.size() + l2.size());
        mergedList.insert(mergedList.end(), l1.begin(), l1.end());
        mergedList.insert(mergedList.end(), l2.begin(), l2.end());
        sort(mergedList.begin(), mergedList.end());
        return mergedList;
    }
}
