    public int[] mergeTwoLists(int[] l1, int[] l2) {
        int n1 = l1.length, n2 = l2.length;
        int[] merged = new int[n1 + n2];
        int i = 0, j = 0, k = 0;
        while (i < n1 && j < n2) {
            if (l1[i] <= l2[j]) {
                merged[k++] = l1[i++];
            }
            else {
                merged[k++] = l2[j++];
            }
        }
        while (i < n1) {
            merged[k++] = l1[i++];
        }
        while (j < n2) {
            merged[k++] = l2[j++];
        }
        return merged;
    }
}

